import re

def strip_markdown(text: str) -> str:
    """Strip markdown before TTS — asterisks and hashes are read literally."""
    return re.sub(r'[*_`#>]', '', text).strip()

def truncate_history(history: list, max_turns: int = 10) -> list:
    """Keep system prompt + last max_turns user/assistant pairs."""
    system = [m for m in history if m["role"] == "system"]
    turns = [m for m in history if m["role"] != "system"]
    return system + turns[-(max_turns * 2):]
